<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Library';
if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf(); $form=post('form'); if($form==='book'){executeSql('INSERT INTO books(isbn,title,author,total_copies,available_copies) VALUES (?,?,?,?,?)',[post('isbn'),post('title'),post('author'),(int)post('total_copies','1'),(int)post('total_copies','1')]);} elseif($form==='issue'){executeSql('INSERT INTO book_issues(book_id,student_id,issue_date,due_date) VALUES (?,?,?,?)',[(int)post('book_id'),(int)post('student_id'),post('issue_date'),post('due_date')]); executeSql('UPDATE books SET available_copies=GREATEST(available_copies-1,0) WHERE id=?',[(int)post('book_id')]);} elseif($form==='return'){ $issue=(int)post('issue_id'); $i=fetchOne('SELECT due_date,book_id FROM book_issues WHERE id=?',[$issue]); $fine=0; if($i){$late=max(0,(strtotime(date('Y-m-d'))-strtotime($i['due_date']))/86400); $fine=$late*5; executeSql('UPDATE book_issues SET return_date=CURDATE(), fine=? WHERE id=?',[$fine,$issue]); executeSql('UPDATE books SET available_copies=available_copies+1 WHERE id=?',[$i['book_id']]); }} header('Location: index.php'); exit; }
$books=fetchAll('SELECT * FROM books ORDER BY id DESC'); $students=fetchAll('SELECT id,full_name FROM students ORDER BY full_name'); $issues=fetchAll('SELECT bi.*,b.title,s.full_name FROM book_issues bi JOIN books b ON b.id=bi.book_id JOIN students s ON s.id=bi.student_id ORDER BY bi.id DESC'); include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><h5>Add Book</h5><form method="post" class="row g-2"><?=csrfField()?><input type="hidden" name="form" value="book"><div class="col"><input name="isbn" class="form-control" placeholder="ISBN"></div><div class="col"><input name="title" class="form-control" placeholder="Title"></div><div class="col"><input name="author" class="form-control" placeholder="Author"></div><div class="col"><input name="total_copies" type="number" class="form-control" value="1"></div><div class="col"><button class="btn btn-primary">Add</button></div></form><hr><h5>Issue Book</h5><form method="post" class="row g-2"><?=csrfField()?><input type="hidden" name="form" value="issue"><div class="col"><select name="book_id" class="form-select"><?php foreach($books as $b):?><option value="<?=$b['id']?>"><?=e($b['title'])?> (<?=$b['available_copies']?>)</option><?php endforeach;?></select></div><div class="col"><select name="student_id" class="form-select"><?php foreach($students as $s):?><option value="<?=$s['id']?>"><?=e($s['full_name'])?></option><?php endforeach;?></select></div><div class="col"><input type="date" name="issue_date" value="<?=date('Y-m-d')?>" class="form-control"></div><div class="col"><input type="date" name="due_date" value="<?=date('Y-m-d',strtotime('+7 days'))?>" class="form-control"></div><div class="col"><button class="btn btn-primary">Issue</button></div></form><hr><table class="table"><tr><th>Book</th><th>Student</th><th>Issue</th><th>Return</th><th>Fine</th><th></th></tr><?php foreach($issues as $i):?><tr><td><?=e($i['title'])?></td><td><?=e($i['full_name'])?></td><td><?=$i['issue_date']?></td><td><?=$i['return_date']?:'-'?></td><td><?=$i['fine']?></td><td><?php if(!$i['return_date']):?><form method="post" class="d-inline"><?=csrfField()?><input type="hidden" name="form" value="return"><input type="hidden" name="issue_id" value="<?=$i['id']?>"><button class="btn btn-sm btn-warning">Return</button></form><?php endif;?></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
